import{o as p,c as t,D as e}from"./framework.fdb046e2.js";const a='{"title":"Глава 12","description":"","frontmatter":{"title":"Глава 12","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-08-20T00:00:00.000Z"},"headers":[{"level":2,"title":"Двенадцатая глава","slug":"двенадцатая-гnава"}],"relativePath":"texts/malini-vijayottara/12.md","lastUpdated":1624912940834}',r={},l=e('<h2 id="двенадцатая-гnава"><a class="header-anchor" href="#двенадцатая-гnава" aria-hidden="true">#</a> Двенадцатая глава</h2><p>Затем с воодушевлением выслушав эту речь Бога богов, чрезвычайно ясную, творящая блаженство миру;.1.</p><p>Довольная, удовлетворенная, бессмертием Деви, почитаемая сонмом богов, поклонившись Уничтожителю слепоты, вновь сказала Бхарати:.2.</p><p>Прежде Тобой было сказано, что йогин должен практиковать йогу. Как же совершается эта практика? Поведай о Губитель Трипуры!.3.</p><p>На сказанное так Владычицей вселенной, Бхарава, устранитель страха, сказал глубоко удовлетворенный такую мудрую речь: .4.</p><p>Услышь (истину) о практике йоги, поведанную мною ранее. Устойчиво пребывая в ней, в этом мире йогин обретет сиддхи ..5.</p><p>В пещере или землянке, в беззвучном радующем ум (месте), лишенном всех помех, йогин должен практиковать йогу ..6.</p><p>Победивший асану, победивший ум, победивший прану, победивший чувства, победивший сон, победивший гнев, победивший порывы и пребывающий (в этом состоянии).7.</p><p>Владыка йоги должен практиковать посредством различения всех объектов, различения ума, (различения таттв) начиная с земли и заканчивая Шакти ..8.</p><p>Различение пространства, символа (виграха), бинду, варны, бхуваны и адхвы- таковы шесть различений, как о них наставляется ..9.</p><p>Различение внутреннего внешнего, и соединяющее (их)- так именуются три вида пространства (вйома). Бинду именуется десятеричным ..10.</p><p>Кадамбаголакара, сияющая светом мерцающей звезды, подразделяемая на белый прочие (цвета)- такова единая десятеричная бинду ..11.</p><p>Колокольчик, чиравака и т.д.- таков звук, десятерично подразделяемый. Виграха – собственное «я» (ану), пребывающее в двойственности, хотя оно множественно ..12.</p><p>У миров нет числа, число варн – полсотни. Что-то одно для практики следует выбрать, для соединения с этим ..13.</p><p>Другое к плодам не приводит. Это именуются ведущим к разделенности. У него один плод – в нем разделение ума ..14.</p><p>Душа, очищенная хомой и дикшей обученная относительно вхождения (самавеша), желающая обрести йогу должна вначале выполнять (эту практику) ..15.</p><p>Поместив на обе руки высшую биджу, пусть мудрый, посредством махамудры, в обратном порядке созерцает Шакти;.16.</p><p>Сияющую, как пламя огня, от кончиков стоп до макушки. Затем следует выполнить намаскар. Так созерцается в сердце огонь ..17.</p><p>В изначальной форме следует созерцать высшую биджу, чрезвычайно яркую. Ее следует созерцать три матры, исходящую из трех КА и КХА ..18.</p><p>Затем, после ста тала, йогин обретет вхождение (в нее) за семь дней, даже если он –убийца брахмана. (Так) он должен практиковать ежедневно ..19.</p><p>С телом, наделенным такой авешей, следует совершить это правило как было описано ..20а.</p><p>Как было (описано) учителем, выполняется последовательно правило авеши.</p><p>Псоредством созерцания васан, следует приступить к овладению ступенями (йоги).</p><p>Поклонившись Гананатхе, следует созерцать последовательность трех гуру, тогда его тело охватывается (этим сотсоянием). Следует созерцать, с умом не отклоняющимся ни на что иное, в своем теле, сияющий как золото четырехугольник, наделенный ваджрами ..22.</p><p>Затем обретется тяжесть (гарима) за двадцать семь дней. За семь дней он победит его (тела) инертность ..23.</p><p>За шесть месяцев он станет победившим болезни с текучим телом. За три года (он обретет) ваджрное тело, за девять превзойдет нагов ..24.</p><p>Поведана Тебе чистая притхиви дхарана. Теперь как прежде, о Деви, поведаю тебе о ее пятеричном подразделении ..25.</p><p>Слева и справа следует созерцать тело, сияющее подобно расплавленному золоту, пребывающее в четырехугольной мандале, украшенной ваджрами ..26.</p><p>За семь дней оно обретет тяжесть. За месяц оно освободится от болезней. За шесть месяцев йогин, пребывающий внутри земли, воистину, будет знать все ..27.</p><p>За три года он получит все наслаждения на земле, окруженной семью океанами. Второе различение поведано, теперь услышь о третьем ..28.</p><p>Следует созерцать тело, как есть, но лишенное деятельности. (Тогда йогин) обретет плод описанный ранее, вместе с паталой ..29.</p><p>При четвертом (различении), следует созерцать (тело) пребывающее в сердце размером в двенадцать ангул, с первой варной в собственной форме, слева и справа неусыпно ..30.</p><p>Обретя все, описанное ранее, он станет владыкой паталы. Он достигнет этой устойчивости в недеянии. В пятом (разделении);.31.</p><p>(Созерцается тело) желтое сияющее как солнце. При шестом- черное и массивное. При седьмом следует тщательно созерцать его плещущимся.32.</p><p>Затем он устойчиво будет знать три (мира): бхур, бхувар и свар, и другие (миры), за описанное прежде количество лет ..33.</p><p>(Следует созерцать) Сакалу пребывающую внутри сердца и Себя (Атман) цвета золота, самосияющего, излучающего весь свет изнутри тела ..34.</p><p>Разделение на правое и левое и семь миров, как и прежде, мудрый устойчиво познает внаслаждении в этом, девятом разделении ..35.</p><p>Следует созерцать солнечный диск, желтый как прежде. Так он обретет мир Брахмана, описанным выше путем ..36.</p><p>Затем следует созерцать его свет, сияющий, желтый как и прежде. (Тогда), став равным Мне, он достигнет Моего мира ..37.</p><p>Следует созерцать свет, желтый, все освещающий внутри и снаружи. (Тогда он) обретет господство на Шатарудрами ..38.</p><p>Так практикуется пятнадцатиричное созерцание притхиви таттвы йогинами, ради совершенства в йоге желающими ее плодов ..39.</p><p>Созревание готовности (к ней) зависит от васан. С ней следует стартельно установить соединение во время дикши ..40.</p><p>Кто соединен с этой таттвой, тот не возращается из нее. Обретя все ее плоды, соединенный с Шивой не разъединится ..41.</p><p>Даже не соединенный, благодаря очищению свыше обретет владычество над мирами. Благодаря очищению он обретет природу Шивы, сожгя оковы самсары ..42. [small]Такова в священной «Малини виджайоттара тантре» двенадцатая глава&lt;[/small]</p>',44);r.render=function(e,a,r,i,s,n){return p(),t("div",null,[l])};export default r;export{a as __pageData};
